export default defineComponent({
props: {
hookdeck: {
type: "app",
app: "hookdeck",
},
async run({steps, $}) {
return await axios($, {
url: `https://api.hookdeck.com/2023-01-01/events`,
headers: {
Authorization: `Bearer ${this.hookdeck.$auth.api_key}`,
"Content-Type": `application/json`,
},
})
},
})
